def ridge_regression(X, y, lam=0.1, lr=0.01, epochs=500):
    """Linear regression with L2 (Ridge) regularisation."""
    n, d = len(X), len(X[0])
    w = [0.0] * d
    for _ in range(epochs):
        for i in range(n):
            pred  = sum(w[j]*X[i][j] for j in range(d))
            error = pred - y[i]
            for j in range(d):
                grad_mse = error * X[i][j]
                w[j] -= lr * (grad_mse + ___________) / n
    return w

