    """Linear regression with L1 (Lasso) regularisation."""
    n, d = len(X), len(X[0])
    w = [0.0] * d
    for _ in range(epochs):
        for i in range(n):
            pred  = sum(w[j]*X[i][j] for j in range(d))
            error = pred - y[i]
            for j in range(d):
                grad_mse = error * X[i][j]
